Expr = Union[
    Tuple[str, int],
    Tuple[str, tuple, tuple],
]


def read_numbers(path: str) -> List[int]:
    with open(path, "r", encoding="utf-8") as f:
        data = f.read().split()
    return [int(x) for x in data]


def build_graph(expr: Expr) -> Tuple[nx.Graph, int]:
    """Return (G, root) for the rooted expression."""
    tag = expr[0]
    if tag == "s":
        _, sid = expr
        n, edges, root = SEEDS[sid]
        G = nx.Graph()
        G.add_nodes_from(range(n))
        G.add_edges_from((u, v) for u, v in edges)
        return G, root

    if tag == "m":
        _, e1, e2 = expr
        G1, r1 = build_graph(e1)
        G2, r2 = build_graph(e2)

        max1 = max(G1.nodes()) if G1.number_of_nodes() else -1
        mapping = {}
        next_id = max1 + 1
        for v in G2.nodes():
            if v == r2:
                mapping[v] = r1
            else:
                mapping[v] = next_id
                next_id += 1

        H2 = nx.relabel_nodes(G2, mapping, copy=True)
        G = nx.compose(G1, H2)
        return G, r1

    if tag == "a":
        _, e1, e2 = expr
        G1, r1 = build_graph(e1)
        G2, r2 = build_graph(e2)

        mapping1 = {v: v + 1 for v in G1.nodes()}
        H1 = nx.relabel_nodes(G1, mapping1, copy=True)

        offset = (max(H1.nodes()) + 1) if H1.number_of_nodes() else 1
        mapping2 = {v: v + offset for v in G2.nodes()}
        H2 = nx.relabel_nodes(G2, mapping2, copy=True)

        G = nx.Graph()
        G.add_node(0)
        G = nx.compose(G, H1)
        G = nx.compose(G, H2)
        G.add_edge(0, mapping1[r1])
        G.add_edge(0, mapping2[r2])
        return G, 0

    raise ValueError(f"unknown expression tag: {tag}")


def independent_set_count(G: nx.Graph) -> int:
    """
    Exact count of independent sets using the recurrence
        i(G) = i(G - v) + i(G - N[v])
    on bitmasks.
    """
    nodes = list(G.nodes())
    n = len(nodes)
    index = {v: i for i, v in enumerate(nodes)}
    closed = [0] * n
    for v in nodes:
        i = index[v]
        mask = 1 << i
        for u in G.neighbors(v):
            mask |= 1 << index[u]
        closed[i] = mask

    @functools.lru_cache(maxsize=None)
    def solve(mask: int) -> int:
        if mask == 0:
            return 1
        # choose the highest set bit
        bit = 1 << (mask.bit_length() - 1)
        i = bit.bit_length() - 1
        return solve(mask ^ bit) + solve(mask & ~closed[i])

    return solve((1 << n) - 1)


def verify_target(n: int, verbose: bool = False) -> Dict[str, object]:
    if n not in WITNESSES:
        return {
            "n": n,
            "ok": False,
            "reason": "no stored witness for this value",
        }

    G, root = build_graph(WITNESSES[n])
    count = independent_set_count(G)
    connected = nx.is_connected(G)
    planar, _ = nx.check_planarity(G)

    ok = (count == n) and connected and planar
    result = {
        "n": n,
        "ok": ok,
        "count": count,
        "connected": connected,
        "planar": planar,
        "vertices": G.number_of_nodes(),
        "edges": G.number_of_edges(),
        "root": root,
        "edge_list": sorted(tuple(sorted(e)) for e in G.edges()),
    }

    if verbose:
        print(
            f"n={n:>6}  ok={ok}  "
            f"i(G)={count:>6}  "
            f"|V|={G.number_of_nodes():>2}  |E|={G.number_of_edges():>2}"
        )

    return result


def compare_with_input(input_numbers: Sequence[int]) -> None:
    built_in = set(TARGETS)
    incoming = set(input_numbers)
    only_in_input = sorted(incoming - built_in)
    only_in_builtin = sorted(built_in - incoming)

    if not only_in_input and not only_in_builtin:
        print("Input list matches the built-in target list exactly.")
        return

    print("Input list differs from the built-in target list.")
    if only_in_input:
        print("Only in input:", only_in_input[:20], "..." if len(only_in_input) > 20 else "")
    if only_in_builtin:
        print("Only in built-in list:", only_in_builtin[:20], "..." if len(only_in_builtin) > 20 else "")


def main(argv: Sequence[str] | None = None) -> int:
    parser = argparse.ArgumentParser(
        description="Verify connected planar witnesses for the built-in list."
    )
    parser.add_argument(
        "file",
        nargs="?",
        help="optional whitespace-separated file of integers to compare/verify",
    )
    parser.add_argument(
        "--show",
        type=int,
        metavar="N",
        help="print the witness edge list for a specific N",
    )
    parser.add_argument(
        "--quiet",
        action="store_true",
        help="suppress per-number progress output",
    )
    args = parser.parse_args(argv)

    if args.file:
        input_numbers = read_numbers(args.file)
        compare_with_input(input_numbers)
        targets = sorted(set(input_numbers))
    else:
        targets = TARGETS

    missing = [n for n in targets if n not in WITNESSES]
    if missing:
        print("No stored witnesses for:", missing)
        return 1

    bad = []
    max_v = 0
    max_e = 0
    for n in targets:
        result = verify_target(n, verbose=not args.quiet)
        max_v = max(max_v, int(result["vertices"]))
        max_e = max(max_e, int(result["edges"]))
        if not result["ok"]:
            bad.append(result)

    print()
    print(f"Verified {len(targets)} target values.")
    print(f"Maximum witness size: |V|={max_v}, |E|={max_e}.")

    if bad:
        print(f"Failures: {len(bad)}")
        for item in bad[:10]:
            print(item)
        return 1

    print("All verified witnesses are connected, planar, and have the required number of independent sets.")

    if args.show is not None:
        if args.show not in WITNESSES:
            print(f"No witness stored for N={args.show}.")
            return 1
        info = verify_target(args.show, verbose=False)
        print()
        print(f"Witness for N={args.show}:")
        print(f"  |V| = {info['vertices']}")
        print(f"  |E| = {info['edges']}")
        print(f"  edge list = {info['edge_list']}")

    return 0


if __name__ == "__main__":
    raise SystemExit(main())
